<template>
    <div class="login-container">
    <div class="login-form">
      <h2>로그인</h2>
      <div class="input-container">
        <input 
          id="email" 
          class="input-field" 
          type="email" 
          v-model="user.email"
          placeholder=" ">
        <label class="floating-label" for="email">이메일</label>
      </div>
      <div class="input-container password-container">
        <input 
          id="password" 
          class="input-field" 
          :type="isShowPassword ? 'text' : 'password'" 
          v-model="user.password"
          placeholder=" ">
        <label class="floating-label" for="password">비밀번호</label>
        <button type="button" class="password-hidetoggle" @click="showPasswordToggle">
          <img 
            :src="isShowPassword ? require('@/assets/open-eye.svg') : require('@/assets/close-eyes.svg')" 
            :alt="isShowPassword ? '비밀번호 숨기기' : '비밀번호 표시'"
          >
        </button>
      </div>
      <button class="login-button" @click="handleLogin">로그인</button>
      <div class="options">
        <label class="keep-log">
          <input type="checkbox" v-model="keepLogin"> 로그인 유지
        </label>
        <div class="links">
          <a href="#">아이디 찾기</a>
          <a href="#">비밀번호 찾기</a>
          <a href="#">회원가입</a>
        </div>
      </div>
      <div class="naver-login-btn">NAVER</div>
    </div>
  </div>
</template>
<script>
import { mapActions } from 'vuex'

export default {
    name:'routeLogin',
    components:{
        
    },
    data(){
        return {
            user: {
                email: '',
                password: ''
            },
            isShowPassword: false,
            keepLogin: false
        }
    },
    methods:{
        ...mapActions(['login']),
        
        async handleLogin() {
            try {
                if (!this.user.email || !this.user.password) {
                    alert('아이디/비밀번호를 입력해주세요.');
                    return;
                }

               const response = await fetch('http://localhost:8000/user/login',{
                    credentials: 'include',
                    method: 'POST',
                    headers:{
                        'Content-Type':'application/json',
                        'Accept': 'application/json',
                        'Access-Control-Allow-Credentials': 'true'
                    },
                    body:JSON.stringify({
                        ...this.user,
                        keepLogin: this.keepLogin
                    })
                })
                if(!response.ok){
                    alert('로그인 실패');
                    return
                }

                const res = await response.json()
                // console.log(res);
                
                // Vuex store의 login action 호출
                await this.login(res.content.user_id_hash || {})

                // 리다이렉트 처리
                const redirectPath = this.$route.query.redirect || '/'
                this.$router.push(redirectPath)
            } catch {
                alert('로그인을 실패했습니다. 담당자에게 문의');
            }
        },
        showPasswordToggle(){
            this.isShowPassword = !this.isShowPassword;
        }
    }
}
</script>
