<template>
    <div class="routeHome">
        <mainBanner></mainBanner>
        <mainCategory></mainCategory>
        <liveGridLayout :globalChzzkLiveList='globalChzzkLiveList'></liveGridLayout>
    </div>
</template>
<script>
import liveGridLayout from '@/components/layout/liveGridLayout.vue';
import mainBanner from '@/components/layout/mainBanner.vue';
import mainCategory from '@/components/navgation/mainCategory.vue';

export default {
    name:'routeHome',
    components:{
        liveGridLayout,
        mainBanner,
        mainCategory
    },
    data(){
        return {
            globalChzzkLiveList:{},
        }
    },
    mounted(){
        this.loadChzzkLiveTop20();
    },
    methods:{
        async loadChzzkLiveTop20(){
            try{
                const response = await fetch('http://localhost:8000/chzzk/popular', {
                    methods:'GET',
                    headers:{
                        'Content-Type':'application/json'
                    }
                });

                const res = await response.json();

                if (res['status_code'] == 200) {
                    this.globalChzzkLiveList = res['content']['data'];
                }

                return ;
            } catch{
                alert("인기방송 불러오기 실패");
            }
        }
    }
}
</script>
<style scoped>
.routeHome {
    padding-top: 70px;
    min-height: calc(100vh - 50px);
    width: 100%;
}
</style>