import {createStore} from 'vuex'

export default createStore({
    state : {
        user: null,
        isLoggedIn: false,
    },
    mutations: {
        setUser(state, user){
            state.user = user;
            state.isLoggedIn = true;
        },
        logout(state) {
            state.user = null;
            state.isLoggedIn = false;
        }
    },
    actions:{
        async checkSession({commit}) {
            try {
                const response = await fetch('http://localhost:8000/user/session', {
                    credentials: 'include'  // 세션 쿠키 전송을 위해 필수
                });
                
                if (response.ok) {
                    const data = await response.json();
                    // content가 비어있지 않은 경우에만 로그인 상태로 설정
                    if (data.content && Object.keys(data.content).length > 0) {
                        commit('setUser', data.content);
                        return true;
                    } else {
                        commit('logout');
                        return false;
                    }
                } else {
                    commit('logout');
                    return false;
                }
            } catch (error) {
                console.error('세션 체크 실패:', error);
                commit('logout');
                return false;
            }
        },
        async login({commit}, user){
            try {
                commit('setUser', user);
            }catch(error){
                console.log('로그인 실패');
                commit('logout');
            }
        },
        logout({commit}){
            commit('logout');
        }
    },
    getters: {
        isLoggedIn: state => state.isLoggedIn,
        user: state => state.user
    }
})