<template>
    <div class="studio-layout">
        <div class="channel-profile">
            <div class="image-container">
                <aImgTag class="channel-image" :href="''" :size="'110'" :filename="channelImageUrl" :isOnline="true"></aImgTag>
            </div>
            <div class="channel-info">
                <subTitle class="channelName" :title="channelInfo['channelName']" fontWeight="40"></subTitle>
                <a class='chzzk-link' href="#">치지직 보기 ></a>
            </div>
        </div>
        <div class="channel-analysis">
            <categoryNav></categoryNav>
        </div>
    </div>
</template>
<script>
import aImgTag from '@/common/aImgTag.vue'
import subTitle from '@/common/subTitle.vue'
import categoryNav from '@/common/categoryNav.vue';

export default {
    name:'studioLayout',
    components:{
        aImgTag,
        subTitle,
        categoryNav
    },
    data(){
        return {
            channelInfo:{},
            channelImageUrl:''
        }
    },
    methods:{
        async loadChannelinfo(){
            const api = 'http://localhost:8000/chzzk/channels/' + this.$route.params.channelId;

            try{
                const response = await fetch(api, {
                    method:'GET',
                    credentials:'include',
                    headers :{
                        'Content-Type':'application/json'
                    }
                });

                const res = await response.json();

                if(res.status_code == 400){
                    alert('정보를 불러오지 못했습니다.');
                    location.href = "/";
                }

                this.channelInfo = res.content;
                this.channelImageUrl = this.channelInfo.channelImageUrl;
            }catch {
                alert('정보를 불러오지 못했습니다.3');
                location.href = "/";
            }
        }
    },
    async mounted(){
        this.loadChannelinfo();
    }
}
</script>
