<template>
  <topHeader v-if='showNav' :isLoggedIn='isLoggedIn' :user='user'></topHeader>
  <leftSideNav v-if='showNav'></leftSideNav>
  <router-view :user='user'></router-view>
</template>

<script>
import topHeader from '@/components/navgation/topHeader.vue';
import leftSideNav from '@/components/navgation/leftSideNav.vue';
import {mapState, mapActions} from 'vuex';
import {useRoute} from 'vue-router'

export default {
  name: 'App',
  components: {
    topHeader,
    leftSideNav
  },
  computed: {
    ...mapState(['isLoggedIn', 'user']),
    showNav() {
      const hiddenRoutes = ['/login', '/register', '/settings']
      return !hiddenRoutes.includes(this.route.path)
    }
  },
  data() {
    return {
      route: useRoute()
    }
  },
  methods: {
    ...mapActions(['checkSession'])
  },
  async created() {
    // 앱 시작 시 세션 상태 확인
    await this.checkSession();
  }
}
</script>

