import { createRouter, createWebHistory } from 'vue-router'
import routeHome from '@/components/route/routeHome.vue'
import routeLive from '@/components/route/routeLive.vue'
import routeStudio from '@/components/route/routeStudio.vue'
import routeLogin from '@/components/route/routeLogin.vue'
import routeSettings from '@/components/route/routeSettings.vue'
import store from '@/store'

const routes = [
  {path:'', name:'home', component:routeHome},
  {path:'/live/:liveid', name:'live', component:routeLive, meta: { requiresAuth: true }},
  {
    path:'/live/:liveid', 
    name:'live', 
    component:routeLive, 
    meta: { 
      requiresAuth: true,
      title: '라이브' // 페이지 제목 추가
    }
  },
  {
    path:'/studio/:channelId', 
    name:'studio', 
    component:routeStudio, 
    meta: { 
      requiresAuth: true,
      title: '스튜디오'
    }
  },
  {
    path:'/login', 
    name:'login', 
    component:routeLogin
  },
  {
    path:'/settings', 
    name:'settings', 
    component:routeSettings, 
    meta: { 
      requiresAuth: true,
      title: '설정'
    }
  }
]

const router = createRouter({
  history: createWebHistory(),
  routes
})

// 네비게이션 가드 설정
router.beforeEach(async (to, from, next) => {
  // 로그인이 필요한 페이지인지 확인
  if (to.matched.some(record => record.meta.requiresAuth)) {
    try {
      // 세션 상태 체크
      await store.dispatch('checkSession')
      
      // 로그인 상태 확인
      if (!store.state.isLoggedIn) {
        // 알림 메시지 표시 (페이지 제목이 있는 경우 포함)
        const pageTitle = to.meta.title ? `${to.meta.title} ` : ''
        alert(`${pageTitle}페이지는 로그인이 필요한 서비스입니다.`)
        
        // 로그인이 되어있지 않으면 로그인 페이지로 리다이렉트
        next({
          path: '/login',
          query: { redirect: to.fullPath }  // 로그인 후 돌아올 페이지 저장
        })
      } else {
        next()  // 로그인 되어있으면 진행
      }
    } catch (error) {
      console.error('세션 체크 실패:', error)
      next({
        path: '/login',
        query: { redirect: to.fullPath }
      })
    }
  } else {
    // 로그인이 필요없는 페이지는 그대로 진행
    next()
  }
})

export default router
